import { defineConfig } from 'vitepress';
import { globbySync } from "globby";
import * as path from "path";
import { fileURLToPath } from 'url'
import vueLiveMd from './vue-live-md-it.mjs';
import eslint from 'vite-plugin-eslint';
import autoprefixer from 'autoprefixer';
import postcssImport from 'postcss-import';
import postcssDiscardComments from 'postcss-discard-comments';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// get all the components generated by vue-docgen-cli
const sidebarComponents = globbySync('components/**/*.md', { cwd: path.resolve(__dirname, '../')})

import pJson from '../../package.json';

// https://vitepress.dev/reference/site-config
export default defineConfig({
  base: '/base-ui-components/',
  title: `base UI components v${pJson.version}`,
  description: 'A styleguide for base UI components, a component library for the university of Applied Arts Vienna',
  head: [
    ['meta', { name: 'theme-color', content: '#ffffff' }],
    ['meta', { name: 'apple-mobile-web-app-capable', content: 'yes' }],
    ['meta', { name: 'apple-mobile-web-app-status-bar-style', content: 'black' }],
    ['meta', { name: 'viewport', content: 'width=device-width, initial-scale=1' }],
    ['meta', { name: 'apple-mobile-web-app-title', content: 'base' }],
    ['meta', { name: 'application-name', content: 'base' }],
    ['meta', { name: 'apple-mobile-web-app-status-bar-style', content: 'black' }],
    ['link', { rel: 'apple-touch-ico', sizes: '180x180', href: '/apple-touch-icon.png' }],
    ['link', { rel: 'icon', type: 'image/png', sizes: '32x32', href: '/favicon-32x32.png' }],
    ['link', { rel: 'icon', type: 'image/png', sizes: '16x16', href: '/favicon-16x16.png' }],
    ['link', { rel: 'mask-icon', sizes: '180x180', href: '/safari-pinned-tab.svg' }],
    ['script', {}, 'var base_ui_icons = "/base-ui-components/base-ui-icons.svg";']
  ],
  // to preload the font file
  transformHead({ assets }) {
    const myFontFile = assets.find(() => /source-sans-pro-v13-latin_latin-ext\.\w+\.woff2/)
    if (myFontFile) {
      return [
        [
          'link',
          {
            rel: 'preload',
            href: myFontFile,
            as: 'font',
            type: 'font/woff2',
            crossorigin: ''
          }
        ]
      ]
    }
  },
  cleanUrls: true,
  outDir: path.resolve(__dirname, '../../styleguide'),
  vite: {
    plugins: [
      eslint(),
    ],
    resolve: {
      alias: {
        'styles': path.resolve(__dirname, './styles'),
        '@': path.resolve(__dirname, '../../src'),
      },
    },
    css: {
      preprocessorOptions: {
        scss: {
          additionalData: `
            @use "@/styles/variables" as *;
        `,
          api: 'modern-compiler', // or "modern"
          // currently deprecation warnings from sass concerning legacy js API and from
          // datepicker - added the two settings below to not pollute console
          silenceDeprecations: ['legacy-js-api', 'import'],
          quietDeps: true,
        },
      },
      postcss: {
        // the configuration was defined here (and not in an external file)
        // to prevent in a npm-link-setup the plugins from being requested in the parent module
        plugins: [
          autoprefixer(),
          // needed for import of external css (e.g. leaflet)
          // needs to be before postcss-url to have leaflet background-images included
          postcssImport(),
          // remove comments
          postcssDiscardComments(),
        ],
      },
    },
  },
  rewrites: {
    // don't have components running under /components but at root
    // useful thing here: old links (in changelog) with /components in path will automatically
    // be redirected
    'components/:component': ':component',
  },
  themeConfig: {
    // https://vitepress.dev/reference/default-theme-config
    repo: 'https://github.com/base-angewandte/base-ui-components',
    lastUpdated: true,
    aside: 'left',
    editLink: false,
    // TODO: adding a footer would probably make sense?
    footer: {
      message: 'Released under the MIT License.',
      copyright: 'Copyright © 2019-present Evan You'
    },
    nav: [
      {
        text: 'Components',
        // here we need to use /components not '/' do be able to distinguish between
        // landing page (index.md) and components.md page
        // components.md is created as hard link since softlink created weird redirects
        link: '/components',
        activeMatch: '/Base*',
      },
      {
        text: 'Customization Options',
        link: '/customization'
      },
      {
        // development.md is created as hard link since softlink created weird redirects
        // to http://localhost:port/buildSetup.md
        text: 'Development',
        link: '/development',
      },
    ],

    sidebar: [
      {
        items: sidebarComponents.map(comp => {
          // remove everything but the component name
          const componentName = comp.replace(/^components\//, '').replace(/\.md$/, '');
          return {
            text: componentName,
            // need to create link without /components so link appears active
            link: '/' + componentName,
          };
        }),
      },
    ],
    search: {
      provider: 'local'
    },

    socialLinks: [
      { icon: 'github', link: 'https://github.com/base-angewandte/base-ui-components' }
    ],
  },
  markdown: {
    config(md){
      md.use(vueLiveMd)
    },
  },
})
